import kotlin.test.*

class IsActiveTest : TestBase() {
    @Test
    fun testContextIsActiveWithoutJob() {
        val context = EmptyCoroutineContext
        // Current behavior: returns false if no job is present
        assertFalse(context.isActive)
    }

