        // Let's check GlobalScope
        assertTrue(GlobalScope.isActive)

        val manualScope = object : CoroutineScope {
            override val coroutineContext: CoroutineContext = EmptyCoroutineContext
        }
        assertTrue(manualScope.isActive)
    }

    @Test
    fun testContextIsActiveWithJob() {
        val job = Job()
        val context = job
        assertTrue(context.isActive)
        job.cancel()
        assertFalse(context.isActive)
    }
}
